"use client";

import { memo, useCallback, useId, useMemo, useState } from "react";
import type { FormEvent, MouseEvent } from "react";
import { CtaOnlyPart } from "./parts/cta-only";
import { InlineFormPart } from "./parts/inline-form";
import {
  DEFAULT_LABELS,
  type NewsletterCardProps,
  type NewsletterCardStatus,
  type ResolvedPartProps,
} from "./types";

/**
 * NewsletterCard01 — brand-tinted CTA card with email signup.
 *
 * Two variants via the `variant` prop:
 * - `inline-form` (default) — email input + Subscribe button.
 * - `cta-only` — full-width button only; for "click to open signup flow" patterns.
 *
 * Form state can be controlled (`value` + `onChange`) or uncontrolled
 * (`defaultValue`). Status (`idle | pending | success | error`) can be
 * controlled (`status` prop) or auto-tracked from a Promise-returning
 * `onSubmit`. Fully i18n via the `labels` prop.
 */
function NewsletterCard01Impl(props: NewsletterCardProps) {
  const {
    variant = "inline-form",
    tone = "primary",
    headingAs = "h3",
    value: controlledValue,
    defaultValue = "",
    onChange,
    onSubmit,
    status: controlledStatus,
    onStatusChange,
    labels: labelsProp,
    className,
    buttonClassName,
    id: idProp,
  } = props;

  const generatedId = useId();
  const baseId = idProp ?? generatedId;
  const titleId = `${baseId}-title`;
  const bodyId = `${baseId}-body`;

  const labels = useMemo(
    () => ({ ...DEFAULT_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const [internalValue, setInternalValue] = useState(defaultValue);
  const isControlled = controlledValue !== undefined;
  const email = isControlled ? controlledValue : internalValue;

  const handleEmailChange = useCallback(
    (next: string) => {
      if (!isControlled) setInternalValue(next);
      onChange?.(next);
    },
    [isControlled, onChange],
  );

  const [internalStatus, setInternalStatus] = useState<NewsletterCardStatus>("idle");
  const status = controlledStatus ?? internalStatus;

  const setStatus = useCallback(
    (next: NewsletterCardStatus) => {
      if (controlledStatus === undefined) setInternalStatus(next);
      onStatusChange?.(next);
    },
    [controlledStatus, onStatusChange],
  );

  const handleSubmit = useCallback(
    (event: FormEvent | MouseEvent) => {
      event.preventDefault();
      if (status === "pending") return;
      if (!onSubmit) return;

      const result = onSubmit(email);

      if (result instanceof Promise) {
        setStatus("pending");
        result
          .then(() => setStatus("success"))
          .catch(() => setStatus("error"));
      }
    },
    [email, onSubmit, setStatus, status],
  );

  const partProps: ResolvedPartProps = {
    variant,
    tone,
    headingAs,
    email,
    onEmailChange: handleEmailChange,
    status,
    labels,
    onSubmit: handleSubmit,
    className,
    buttonClassName,
    titleId,
    bodyId,
  };

  if (variant === "cta-only") return <CtaOnlyPart {...partProps} />;
  return <InlineFormPart {...partProps} />;
}

export const NewsletterCard01 = memo(NewsletterCard01Impl);
NewsletterCard01.displayName = "NewsletterCard01";

export default NewsletterCard01;

export { NewsletterCard01, default } from "./newsletter-card-01";
export type {
  NewsletterCardHeadingLevel,
  NewsletterCardLabels,
  NewsletterCardProps,
  NewsletterCardStatus,
  NewsletterCardTone,
  NewsletterCardVariant,
} from "./types";
export { meta } from "./meta";

import type { FormEvent, MouseEvent } from "react";

export type NewsletterCardVariant = "inline-form" | "cta-only";

export type NewsletterCardTone = "primary" | "accent" | "muted";

export type NewsletterCardStatus = "idle" | "pending" | "success" | "error";

export type NewsletterCardHeadingLevel = "h2" | "h3" | "h4";

export interface NewsletterCardLabels {
  /** Headline. Default: 'Join our newsletter'. */
  title?: string;
  /** Body / description. Default: 'Latest updates, straight to your inbox.'. */
  body?: string;
  /** Email input placeholder. Default: 'Email address'. */
  placeholder?: string;
  /** Email input aria-label. Default: 'Email address'. */
  emailLabel?: string;
  /** Button text. Default: 'Subscribe'. */
  button?: string;
  /** Success message after `onSubmit` resolves. Default: "Thanks! You're subscribed.". */
  successMessage?: string;
  /** Error message after `onSubmit` rejects. Default: 'Something went wrong. Please try again.'. */
  errorMessage?: string;
}

export const DEFAULT_LABELS: Required<NewsletterCardLabels> = {
  title: "Join our newsletter",
  body: "Latest updates, straight to your inbox.",
  placeholder: "Email address",
  emailLabel: "Email address",
  button: "Subscribe",
  successMessage: "Thanks! You're subscribed.",
  errorMessage: "Something went wrong. Please try again.",
};

export interface NewsletterCardProps {
  /** Visual variant. Default: 'inline-form'. */
  variant?: NewsletterCardVariant;

  /** Color tint. Default: 'primary'. */
  tone?: NewsletterCardTone;

  /** Heading semantic level. Default: 'h3'. */
  headingAs?: NewsletterCardHeadingLevel;

  /** Controlled email value. */
  value?: string;
  /** Uncontrolled initial email value. */
  defaultValue?: string;
  /** Email change callback. */
  onChange?: (value: string) => void;

  /** Submit handler. Return Promise to auto-track pending → success/error. */
  onSubmit?: (email: string) => void | Promise<void>;

  /** Controlled status. If omitted, derives from `onSubmit`'s return. */
  status?: NewsletterCardStatus;
  /** Status change callback. */
  onStatusChange?: (status: NewsletterCardStatus) => void;

  /** Localized labels. Defaults are English. */
  labels?: NewsletterCardLabels;

  /** Override classes for the root container. */
  className?: string;
  /** Override classes for the action button. */
  buttonClassName?: string;

  /** Override the heading id. Default: useId(). */
  id?: string;
}

/** Internal shape passed from the root to each variant part. */
export interface ResolvedPartProps {
  variant: NewsletterCardVariant;
  tone: NewsletterCardTone;
  headingAs: NewsletterCardHeadingLevel;
  email: string;
  onEmailChange: (value: string) => void;
  status: NewsletterCardStatus;
  labels: Required<NewsletterCardLabels>;
  onSubmit: (event: FormEvent | MouseEvent) => void;
  className: string | undefined;
  buttonClassName: string | undefined;
  titleId: string;
  bodyId: string;
}

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import type { ResolvedPartProps } from "../types";
import { resolveTone } from "./tone";
import { StatusMessage } from "./status-message";

/**
 * Inline-form variant — email input + Subscribe button in a row.
 * The default for sidebar / footer CTAs that capture email inline.
 */
export function InlineFormPart({
  tone,
  headingAs,
  email,
  onEmailChange,
  status,
  labels,
  onSubmit,
  className,
  buttonClassName,
  titleId,
  bodyId,
}: ResolvedPartProps) {
  const HeadingTag = headingAs;
  const toneClasses = resolveTone(tone);

  return (
    <div
      role="region"
      aria-labelledby={titleId}
      className={cn(
        "rounded-2xl border p-6",
        toneClasses.frame,
        className,
      )}
    >
      <HeadingTag
        id={titleId}
        className={cn("mb-2 font-serif text-lg font-bold", toneClasses.heading)}
      >
        {labels.title}
      </HeadingTag>
      <p id={bodyId} className="mb-4 text-sm text-muted-foreground">
        {labels.body}
      </p>

      <form onSubmit={onSubmit} className="flex gap-2">
        <Input
          type="email"
          required
          value={email}
          onChange={(event) => onEmailChange(event.target.value)}
          placeholder={labels.placeholder}
          aria-label={labels.emailLabel}
          aria-describedby={bodyId}
          aria-invalid={status === "error"}
          disabled={status === "pending"}
          className="flex-1"
        />
        <Button
          type="submit"
          disabled={status === "pending"}
          aria-busy={status === "pending"}
          className={buttonClassName}
        >
          {labels.button}
        </Button>
      </form>

      <StatusMessage status={status} labels={labels} />
    </div>
  );
}

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { ResolvedPartProps } from "../types";
import { resolveTone } from "./tone";
import { StatusMessage } from "./status-message";

/**
 * CTA-only variant — full-width Subscribe button without an email input.
 * For "click to open the signup flow elsewhere" patterns; consumer's
 * `onSubmit` typically opens a modal or navigates.
 *
 * onSubmit is called with an empty string ('') since no email is captured here.
 */
export function CtaOnlyPart({
  tone,
  headingAs,
  status,
  labels,
  onSubmit,
  className,
  buttonClassName,
  titleId,
  bodyId,
}: ResolvedPartProps) {
  const HeadingTag = headingAs;
  const toneClasses = resolveTone(tone);

  return (
    <div
      role="region"
      aria-labelledby={titleId}
      className={cn(
        "rounded-2xl border p-6",
        toneClasses.frame,
        className,
      )}
    >
      <HeadingTag
        id={titleId}
        className={cn("mb-2 font-serif text-lg font-bold", toneClasses.heading)}
      >
        {labels.title}
      </HeadingTag>
      <p id={bodyId} className="mb-4 text-sm text-muted-foreground">
        {labels.body}
      </p>

      <Button
        type="button"
        onClick={onSubmit}
        disabled={status === "pending"}
        aria-busy={status === "pending"}
        className={cn("w-full", buttonClassName)}
      >
        {labels.button}
      </Button>

      <StatusMessage status={status} labels={labels} />
    </div>
  );
}

import type { NewsletterCardStatus, NewsletterCardLabels } from "../types";

/**
 * Status message renderer. Lives below the action area in both variants.
 *
 * - `success` renders in muted text inside an aria-live="polite" region.
 * - `error` renders in destructive text inside a role="alert" region.
 * - `idle` and `pending` render an empty live-region (so the assistive
 *   technology has a stable announcement target when status changes).
 */
export function StatusMessage({
  status,
  labels,
}: {
  status: NewsletterCardStatus;
  labels: Required<NewsletterCardLabels>;
}) {
  if (status === "error") {
    return (
      <div role="alert" className="mt-3 text-sm text-destructive">
        {labels.errorMessage}
      </div>
    );
  }

  return (
    <div aria-live="polite" className="mt-3 min-h-[1.25rem] text-sm text-muted-foreground">
      {status === "success" ? labels.successMessage : null}
    </div>
  );
}

import type { NewsletterCardTone } from "../types";

/**
 * Tone → Tailwind class fragments. Each tone gets a frame (background +
 * border) + a heading color modifier. The frame is `rounded-2xl border p-6`
 * by default, applied at the part level.
 */
const TONE_MAP: Record<NewsletterCardTone, { frame: string; heading: string }> = {
  primary: {
    frame: "border-primary/20 bg-primary/5",
    heading: "text-foreground",
  },
  accent: {
    frame: "border-accent/40 bg-accent/30",
    heading: "text-accent-foreground",
  },
  muted: {
    frame: "border-border/50 bg-muted/40",
    heading: "text-foreground",
  },
};

export const resolveTone = (tone: NewsletterCardTone) => TONE_MAP[tone];
